        'hypnoResponsePh': { TW: '例：是的主人', CN: '例：是的主人', EN: 'e.g. Yes, Master', DE: 'z. B. Ja, Meister', FR: 'ex. Oui, Maître', RU: 'напр. Да, Хозяин', UA: 'напр. Так, Пане' },
