        'sec_stateMsgFx': { TW: '訊息類效果', CN: '信息类效果', EN: 'Message effects', DE: 'Nachrichteneffekte', FR: 'Effets de message', RU: 'Эффекты сообщений', UA: 'Ефекти повідомлень' },
